example.code:
pipeline {
    agent {
        docker {
            image 'node:20-alpine'
            args '-v $HOME/.npm:/root/.npm'
        }
    }

    environment {
        CI = 'true'
    }

    options {
        timeout(time: 30, unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '10'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Install') {
            steps { sh 'npm ci' }
        }

        stage('Validate') {
            parallel {
                stage('Lint') {
                    steps { sh 'npm run lint' }
                }
                stage('Type Check') {
                    steps { sh 'npm run typecheck' }
                }
            }
        }

        stage('Test') {
            steps { sh 'npm test -- --coverage' }
            post {
                always { junit 'junit.xml' }
            }
        }

        stage('Build') {
            steps { sh 'npm run build' }
            post {
                success {
                    archiveArtifacts artifacts: 'dist/**', fingerprint: true
                }
            }
        }

        stage('Deploy') {
            when { branch 'main' }
            input { message 'Deploy to production?'; ok 'Deploy' }
            steps { sh './scripts/deploy.sh production' }
        }
    }

    post {
        always { cleanWs() }
        failure {
            slackSend channel: '#ci', color: 'danger',
                message: "FAILED: ${env.JOB_NAME} #${env.BUILD_NUMBER} (<${env.BUILD_URL}|Open>)"
        }
    }
}

pipeline {
    agent {
        kubernetes {
            yaml '''
apiVersion: v1
kind: Pod
spec:
  containers:
  - name: node
    image: node:20-alpine
    command: [cat]
    tty: true
    resources:
      requests: { cpu: "500m", memory: "512Mi" }
      limits:   { cpu: "1",    memory: "1Gi"  }
  - name: helm
    image: alpine/helm:3.14
    command: [cat]
    tty: true
'''
        }
    }

    stages {
        stage('Build') {
            steps {
                container('node') {
                    sh 'npm ci && npm run build'
                }
            }
        }
        stage('Deploy') {
            steps {
                container('helm') {
                    withCredentials([file(credentialsId: 'kubeconfig', variable: 'KUBECONFIG')]) {
                        sh 'helm upgrade --install myapp ./charts/myapp --wait --timeout 5m'
                    }
                }
            }
        }
    }
}

// vars/standardPipeline.groovy
def call(Map config) {
    pipeline {
        agent { docker { image config.get('image', 'node:20-alpine') } }

        options {
            timeout(time: config.get('timeout', 30), unit: 'MINUTES')
            buildDiscarder(logRotator(numToKeepStr: '10'))
        }

        stages {
            stage('Install') {
                steps { sh config.get('installCmd', 'npm ci') }
            }
            stage('Test') {
                steps { sh config.get('testCmd', 'npm test') }
            }
            stage('Build') {
                steps { sh config.get('buildCmd', 'npm run build') }
            }
            stage('Deploy') {
                when { branch config.get('deployBranch', 'main') }
                steps { sh config.get('deployCmd', 'echo No deploy configured') }
            }
        }

        post {
            always { cleanWs() }
            failure {
                script {
                    if (config.slackChannel) {
                        slackSend channel: config.slackChannel, color: 'danger',
                            message: "FAILED: ${env.JOB_NAME} #${env.BUILD_NUMBER}"
                    }
                }
            }
        }
    }
}
